SELECT name 
FROM officeholders 
WHERE notes LIKE '%accidentally shot himself while collecting specimens%';

SELECT officeholder_id
FROM access_logs
WHERE access_date = (
    SELECT MAX(access_date) 
    FROM access_logs
);

SELECT 
    (SELECT COUNT(*) FROM officeholders) AS total_officeholders,
    (SELECT COUNT(*) FROM users) AS total_users;

SELECT name, term_length
FROM officeholders
WHERE term_length = (
  SELECT MAX(term_length)
  FROM officeholders
);

SELECT DISTINCT officeholder_id, notes
FROM audit_logs
WHERE strftime('%Y', change_date) = '2023';

SELECT name, birth_date, death_date 
FROM officeholders
WHERE officeholder_id = 0;
